{"command": "cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Utils/SimplifyCFG.cpp 5775 5953
bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
                                             IRBuilder<> &Builder) {
  assert(SI->getNumCases() > 1 && "Degenerate switch?");

  bool HasDefault = !SI->defaultDestUnreachable();

  auto *BB = SI->getParent();

  // Partition the cases into two sets with different destinations.
  BasicBlock *DestA = HasDefault ? SI->getDefaultDest() : nullptr;
  BasicBlock *DestB = nullptr;
  SmallVector<ConstantInt *, 16> CasesA;
  SmallVector<ConstantInt *, 16> CasesB;

  for (auto Case : SI->cases()) {
    BasicBlock *Dest = Case.getCaseSuccessor();
    if (!DestA)
      DestA = Dest;
    if (Dest == DestA) {
      CasesA.push_back(Case.getCaseValue());
      continue;
    }
    if (!DestB)
      DestB = Dest;
    if (Dest == DestB) {
      CasesB.push_back(Case.getCaseValue());
      continue;
    }
    return false; // More than two destinations.
  }
  if (!DestB)
    return false; // All destinations are the same and the default is unreachable

  assert(DestA && DestB &&
         "Single-destination switch should have been folded.");
  assert(DestA != DestB);
  assert(DestB != SI->getDefaultDest());
  assert(!CasesB.empty() && "There must be non-default cases.");
  assert(!CasesA.empty() || HasDefault);

  // Figure out if one of the sets of cases form a contiguous range.
  SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
  BasicBlock *ContiguousDest = nullptr;
  BasicBlock *OtherDest = nullptr;
  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
    ContiguousCases = &CasesA;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if (casesAreContiguous(CasesB)) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else {
    // Check if one of the sets can be represented as a (possibly wrapping)
    // range with an offset. Prefer the smaller set for the comparison.
    SmallVectorImpl<ConstantInt *> *RangeCases = nullptr;
    BasicBlock *RangeDest = nullptr;
    BasicBlock *OtherRangeDest = nullptr;
    if (CasesA.size() <= CasesB.size()) {
      RangeCases = &CasesA;
      RangeDest = DestA;
      OtherRangeDest = DestB;
    } else {
      RangeCases = &CasesB;
      RangeDest = DestB;
      OtherRangeDest = DestA;
    }

    // Build a ConstantRange from the case values.
    if (!RangeCases->empty()) {
      // Find min and max values.
      APInt MinVal = (*RangeCases)[0]->getValue();
      APInt MaxVal = (*RangeCases)[0]->getValue();
      for (auto *Case : *RangeCases) {
        const APInt &Val = Case->getValue();
        if (Val.ult(MinVal))
          MinVal = Val;
        if (Val.ugt(MaxVal))
          MaxVal = Val;
      }
      // Create a range [MinVal, MaxVal + 1) which covers all values from
      // MinVal to MaxVal (inclusive). This may be a wrapping range.
      APInt Upper = MaxVal + 1;
      ConstantRange Range(
          MinVal, Upper.isNullValue() ? MinVal : Upper);

      // Check if the range contains exactly the case values.
      bool ExactMatch = Range.isSizeLargerThan(RangeCases->size()) ? false :
        llvm::all_of(*RangeCases, [&Range](ConstantInt *CI) {
          return Range.contains(CI->getValue());
        });

      CmpInst::Predicate Pred;
      APInt RHS, Offset;
      if (ExactMatch && Range.getEquivalentICmp(Pred, RHS, Offset)) {
        // If Offset is non-zero, the range is not contiguous starting from 0
        // but can be made so with an add/sub operation. This handles wrapping
        // ranges like {0, 4, 5} which becomes [0, 1) U [4, 6) and can be
        // checked with (X + -1) u< 3.
        Value *Sub = SI->getCondition();
        Type *Ty = Sub->getType();
        if (!Offset.isNullValue())
          Sub = Builder.CreateAdd(Sub, ConstantInt::get(Ty, Offset),
                                  Sub->getName() + ".off");
        Value *Cmp;
        if (Pred == CmpInst::ICMP_ULT && RHS.isNullValue())
          Cmp = ConstantInt::getTrue(SI->getContext());
        else if (Pred == CmpInst::ICMP_UGE && RHS.isNullValue())
          Cmp = ConstantInt::getFalse(SI->getContext());
        else
          Cmp = Builder.CreateICmp(Pred, Sub, ConstantInt::get(Ty, RHS),
                                   "switch");
        Builder.CreateCondBr(Cmp, RangeDest, OtherRangeDest);

        // Update weight for the newly-created conditional branch.
        if (hasBranchWeightMD(*SI)) {
          SmallVector<uint64_t, 8> Weights;
          getBranchWeights(SI, Weights);
          if (Weights.size() == 1 + SI->getNumCases()) {
            uint64_t TrueWeight = 0;
            uint64_t FalseWeight = 0;
            for (size_t I = 0, E = Weights.size(); I != E; ++I) {
              if (SI->getSuccessor(I) == RangeDest)
                TrueWeight += Weights[I];
              else
                FalseWeight += Weights[I];
            }
            while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
              TrueWeight /= 2;
              FalseWeight /= 2;
            }
            // The branch has been created already, update its weights.
            if (auto *BI = dyn_cast<BranchInst>(BB->getTerminator()))
              setFittedBranchWeights(*BI, {TrueWeight, FalseWeight},
                                     /*IsExpected=*/false, /*ElideAllZero=*/true);
          }
        }

        // Prune obsolete incoming values off the successors' PHI nodes.
        for (auto BBI = RangeDest->begin(); isa<PHINode>(BBI); ++BBI) {
          unsigned PreviousEdges = RangeCases->size();
          if (RangeDest == SI->getDefaultDest())
            ++PreviousEdges;
          for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
            cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
        }
        for (auto BBI = OtherRangeDest->begin(); isa<PHINode>(BBI); ++BBI) {
          unsigned PreviousEdges = SI->getNumCases() - RangeCases->size();
          if (OtherRangeDest == SI->getDefaultDest())
            ++PreviousEdges;
          for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
            cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
        }

        // Clean up the default block.
        if (!HasDefault)
          createUnreachableSwitchDefault(SI, DTU);

        auto *UnreachableDefault = SI->getDefaultDest();

        // Drop the switch.
        SI->eraseFromParent();

        if (!HasDefault && DTU)
          DTU->applyUpdates({{DominatorTree::Delete, BB, UnreachableDefault}});

        return true;
      }
    }

    return false;
  }

  // Start building the compare and branch.

  Constant *Offset = ConstantExpr::getNeg(ContiguousCases->back());
  Constant *NumCases =
      ConstantInt::get(Offset->getType(), ContiguousCases->size());

  Value *Sub = SI->getCondition();
  if (!Offset->isNullValue())
    Sub = Builder.CreateAdd(Sub, Offset, Sub->getName() + ".off");

  Value *Cmp;
  // If NumCases overflowed, then all possible values jump to the successor.
  if (NumCases->isNullValue() && !ContiguousCases->empty())
    Cmp = ConstantInt::getTrue(SI->getContext());
  else
    Cmp = Builder.CreateICmpULT(Sub, NumCases, "switch");
  BranchInst *NewBI = Builder.CreateCondBr(Cmp, ContiguousDest, OtherDest);

  // Update weight for the newly-created conditional branch.
  if (hasBranchWeightMD(*SI)) {
    SmallVector<uint64_t, 8> Weights;
    getBranchWeights(SI, Weights);
    if (Weights.size() == 1 + SI->getNumCases()) {
      uint64_t TrueWeight = 0;
      uint64_t FalseWeight = 0;
      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
        if (SI->getSuccessor(I) == ContiguousDest)
          TrueWeight += Weights[I];
        else
          FalseWeight += Weights[I];
      }
      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
        TrueWeight /= 2;
        FalseWeight /= 2;
      }
      setFittedBranchWeights(*NewBI, {TrueWeight, FalseWeight},
                             /*IsExpected=*/false, /*ElideAllZero=*/true);
    }
  }

  // Prune obsolete incoming values off the successors' PHI nodes.
  for (auto BBI = ContiguousDest->begin(); isa<PHINode>(BBI); ++BBI) {
    unsigned PreviousEdges = ContiguousCases->size();
    if (ContiguousDest == SI->getDefaultDest())
      ++PreviousEdges;
    for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
